function M(m=10){const f=t=>t[Math.floor(Math.random()*t.length)],e=(t,y)=>Math.floor(Math.random()*(y-t+1))+t,p=[];for(let t=0;t<m;t++){const y=f([-1,1]),r=y>0?"<span style='color:#ef4444; font-weight:bold;'>proton (+1)</span>":"<span style='color:#3b82f6; font-weight:bold;'>electron (-1)</span>";let i;t===0?i="e_only":t===1?i="b_only":t===2?i="selector":i=f(["e_only","b_only","selector","complex"]);let c,a,n,l,h=[],x=null,g=null;if(i==="e_only"){c=`Mission ${t+1}: Electric Deflection`,a=`A ${r} is entering a uniform electric field. Use the E-field slider to deflect it into the target zone. Magnetic field is offline.`;const s=e(200,400);n={x:50,y:s,vx:e(80,120),vy:0};const o=s>300?e(100,200):e(400,500);l={x:e(450,550),y:o,r:25},g=0}else if(i==="b_only"){if(c=`Mission ${t+1}: Magnetic Curve`,a=`A ${r} is moving through a magnetic testing chamber. Apply the Right-Hand Rule and use the B-field slider to curve its path into the target. Electric field is offline.`,Math.random()>.5){n={x:e(250,350),y:100,vx:0,vy:e(80,120)};const o=Math.random()>.5;l={x:n.x+(o?200:-200),y:e(350,450),r:25}}else{n={x:100,y:e(250,350),vx:e(80,120),vy:0};const o=Math.random()>.5;l={x:e(350,450),y:n.y+(o?200:-200),r:25}}h=[{x:0,y:0,w:600,h:50},{x:0,y:550,w:600,h:50}],x=0}else if(i==="selector"){c=`Mission ${t+1}: Velocity Selector`;const s=f([50,100,150]),o=f([-2,-1.5,-1,1,1.5,2]),u=o*s;if(Math.random()>.5){const v=o>0?`${o} T (OUT)`:`${Math.abs(o)} T (IN)`;a=`A ${r} must pass through a narrow corridor. The B-field is fixed at <span style='color:#a855f7; font-weight:bold;'>${v}</span>. Calculate and apply the exact E-field required to maintain a straight trajectory ($F_{net} = 0$).`,g=o}else a=`A ${r} must pass through a narrow corridor. The E-field is fixed at <span style='color:#06b6d4; font-weight:bold;'>${u} N/C</span>. Set the B-field to achieve undeflected motion.`,x=u;const d=e(250,350);n={x:50,y:d,vx:s,vy:0},l={x:550,y:d,r:25},h=[{x:150,y:0,w:300,h:d-40},{x:150,y:d+40,w:300,h:600-(d+40)}]}else{c=`Mission ${t+1}: The Cyclotron Trap`,a=`A ${r} needs to navigate a tricky setup. Both fields are manual. Use your knowledge to guide it around the barriers to the target!`,n={x:e(50,100),y:e(100,500),vx:e(80,120),vy:0},l={x:e(400,550),y:e(100,500),r:e(25,35)};const s=(n.x+l.x)/2;Math.random()>.5?h=[{x:s-25,y:0,w:50,h:300}]:h=[{x:s-25,y:300,w:50,h:300}]}p.push({title:c,briefing:a,charge:y,start:n,target:l,obstacles:h,lockedE:x,lockedB:g})}return p}export{M as generateFieldMissions};
